sql:
SELECT * FROM measurements
WHERE researcher_id = 0 AND line >= 2
ORDER BY timestamp ASC;

SELECT * 
FROM researchers 
WHERE researcher_id > 5;

SELECT COUNT(DISTINCT researcher_id)
FROM measurements
WHERE measurement_type = 'microtubule';

SELECT DISTINCT measurement_type
FROM measurements
WHERE measurement_type != 'other' AND measurement_type IS NOT NULL AND measurement_type != '';

external_knowledge:
- 'Certain group of researchers': Refers to researchers with valid email addresses;
- 'Specific range': Refers to mean (2000-3000), standard deviation (<600), minimum (>1000), maximum (<3500), integrated density (4000-5000), raw integrated density (120,000-150,000);
- 'Specialized channel': Refers to a channel with a wavelength of 532 nm and high sensitivity, calibrated in 2023;
- 'Advanced and published': Experiments are either completed or in progress, and their results have been published;
- 'Typical standards for cell research': Procedures involving cell samples and standard protocols.

sql:
SELECT researchers.researcher_id, researchers.first_name, researchers.last_name, researchers.email, user_roles.role_id
FROM researchers
INNER JOIN user_roles ON researchers.researcher_id = user_roles.role_id;
